function handleKeyImportInput(el) {
    const raw = el.value;
    if (!raw.includes('AIza')) return;

    // Extract all instances starting with AIza followed by alphanumeric characters
    const matches = raw.match(/AIza[a-zA-Z0-9_-]+/g);
    if (matches) {
        const uniqueKeys = [...new Set(matches)];
        const structured = uniqueKeys.join('\n');

        // Only update if the content has actually changed to avoid cursor jumping
        if (el.value !== structured) {
            el.value = structured;
            showGlobalToast(`✨ Detected ${uniqueKeys.length} keys`);
        }
    }
}

